// Scoped to .cc-cspd-questions. Generated by microsites/_dversion-build.mjs.
(function () {
  // Use window.document explicitly here — declaring  const document
  // = …  later in this scope hoists the binding to the top of the
  // function as TDZ, so plain  document.querySelector  on this line
  // would throw "Cannot access 'document' before initialization".
  const ROOT = window.document.querySelector('.cc-cspd-questions');
  if (!ROOT) return;

  // Re-bind document.* lookups to resolve against the partial root,
  // so IDs and class selectors can't collide with the host Drupal page.
  const document = new Proxy(window.document, {
    get(target, prop) {
      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));
      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);
      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);
      const v = target[prop];
      return typeof v === 'function' ? v.bind(target) : v;
    },
  });

// ══════════════════════════════════════════
// ASK WIDGET — resident question capture & aggregate
// Uses artifact persistent shared storage (visible to all visitors).
// Falls back to in-memory only if storage is unavailable.
// ══════════════════════════════════════════

const STORAGE_KEY = 'resident_questions_v1';
const MAX_Q_LENGTH = 240;
const MIN_Q_LENGTH = 10;

// category keyword map — each question gets matched to one or "other"
const CATEGORIES = [
  { id: 'q1', label: 'Children & families', anchor: '#q1',
    keywords: ['child', 'kid', 'baby', 'youth', 'teen', 'student', 'school', 'abuse',
               'neglect', 'family', 'parent', 'minor', 'juvenile', 'daycare'] },
  { id: 'q2', label: 'Neighborhood context', anchor: '#q2',
    keywords: ['neighborhood', 'neighbourhood', 'zip', 'area', 'population', 'who lives',
               'my street', 'my block', 'community', 'veteran', 'military', 'fort carson',
               'peterson', 'schriever', 'senior', 'elderly', 'housing'] },
  { id: 'q3', label: 'Budget & taxes', anchor: '#q3',
    keywords: ['tax', 'budget', 'money', 'spend', 'cost', 'fund', 'dollar', 'salary',
               'pay', 'fiscal', 'appropriat', 'revenue', 'expense'] },
  { id: 'q4', label: 'Overall crime', anchor: '#q4',
    keywords: ['crime', 'crimes', 'offense', 'theft', 'robbery', 'burglary', 'assault',
               'violence', 'overall', 'property', 'vandalism', 'drug', 'dui'] },
  { id: 'q5', label: 'Who to call & trust', anchor: '#q5',
    keywords: ['call', 'report', 'trust', 'complaint', 'officer', 'cop', 'misconduct',
               'concern', 'file', 'internal affairs', 'ia ', 'contact', 'phone', 'number',
               '911', 'non-emergency', 'accountab', 'complain', 'discipline'] },
  { id: 'q6', label: 'Shootings (context)', anchor: '#q6',
    keywords: ['shoot', 'shooting', 'gun', 'firearm', 'ois', 'weapon', 'officer-involved',
               'officer involved', 'deadly force'] }
];

function normalize(text) {
  return text.toLowerCase()
    .replace(/[^\w\s']/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function categorize(text) {
  const norm = normalize(text);
  const scores = CATEGORIES.map(cat => {
    let score = 0;
    for (const kw of cat.keywords) {
      if (norm.includes(kw)) score += kw.length >= 5 ? 2 : 1;
    }
    return { cat, score };
  });
  scores.sort((a, b) => b.score - a.score);
  if (scores[0].score === 0) return null; // "other" — a gap
  return scores[0].cat;
}

// basic sanitization — strip HTML tags, limit length, collapse whitespace
function sanitize(text) {
  return String(text)
    .replace(/<[^>]*>/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, MAX_Q_LENGTH);
}

// simple spam/low-quality filter
function isAcceptable(text) {
  if (text.length < MIN_Q_LENGTH) return { ok: false, reason: 'Please write at least a full sentence (10+ characters).' };
  if (text.length > MAX_Q_LENGTH) return { ok: false, reason: 'Please keep your question under 240 characters.' };
  // mostly uppercase
  const upperRatio = (text.match(/[A-Z]/g) || []).length / Math.max(1, (text.match(/[A-Za-z]/g) || []).length);
  if (upperRatio > 0.6 && text.length > 15) return { ok: false, reason: 'Please use normal sentence case, not all caps.' };
  // contains URLs
  if (/https?:\/\/|www\./i.test(text)) return { ok: false, reason: 'Please don\'t include links — describe your question in words.' };
  // repetition
  if (/(.)\1{6,}/.test(text)) return { ok: false, reason: 'That looks like a spam pattern. Please rephrase.' };
  return { ok: true };
}

// fuzzy match by shared significant-word count
function similarityScore(a, b) {
  const STOPWORDS = new Set(['the', 'and', 'for', 'are', 'is', 'in', 'to', 'of', 'a', 'an',
                              'how', 'what', 'where', 'when', 'why', 'who', 'which', 'do',
                              'does', 'did', 'i', 'my', 'me', 'you', 'your', 'we', 'us', 'our',
                              'on', 'at', 'by', 'with', 'from', 'about', 'can', 'would', 'will',
                              'should', 'could', 'it', 'its', 'this', 'that', 'these', 'those',
                              'be', 'been', 'being', 'have', 'has', 'had', 'not']);
  const words = s => new Set(normalize(s).split(' ').filter(w => w.length > 2 && !STOPWORDS.has(w)));
  const wa = words(a), wb = words(b);
  if (!wa.size || !wb.size) return 0;
  let overlap = 0;
  wa.forEach(w => { if (wb.has(w)) overlap++; });
  return overlap / Math.max(wa.size, wb.size);
}

// ─── storage wrapper with graceful fallback ───
let inMemoryQuestions = null;

async function loadQuestions() {
  try {
    if (!window.storage) throw new Error('storage unavailable');
    const res = await window.storage.get(STORAGE_KEY, true);
    if (res && res.value) return JSON.parse(res.value);
  } catch (e) {
    // get() throws when key doesn't exist; that's OK
  }
  return [];
}

async function saveQuestions(questions) {
  // cap at 500 most recent unique questions to stay well under 5MB
  if (questions.length > 500) {
    questions.sort((a, b) => b.lastAsked - a.lastAsked);
    questions = questions.slice(0, 500);
  }
  try {
    if (!window.storage) throw new Error('storage unavailable');
    const res = await window.storage.set(STORAGE_KEY, JSON.stringify(questions), true);
    return !!res;
  } catch (e) {
    console.warn('Save failed:', e);
    inMemoryQuestions = questions;
    return false;
  }
}

// ─── submission handler ───
async function submitQuestion(rawText) {
  const text = sanitize(rawText);
  const check = isAcceptable(text);
  if (!check.ok) return { status: 'reject', message: check.reason };

  const cat = categorize(text);
  const now = Date.now();

  let questions = await loadQuestions();
  if (inMemoryQuestions) questions = inMemoryQuestions;

  // find similar existing question (fuzzy)
  let matched = null;
  let bestSim = 0;
  for (const q of questions) {
    const sim = similarityScore(text, q.text);
    if (sim > bestSim) { bestSim = sim; matched = q; }
  }

  if (matched && bestSim >= 0.6) {
    matched.count = (matched.count || 1) + 1;
    matched.lastAsked = now;
  } else {
    questions.push({
      text, categoryId: cat ? cat.id : 'other',
      count: 1, firstAsked: now, lastAsked: now
    });
  }

  const saved = await saveQuestions(questions);

  const totalCount = matched ? matched.count : 1;
  return {
    status: cat ? 'match' : 'gap',
    category: cat,
    text,
    count: totalCount,
    saved,
    matched: !!matched
  };
}

// ─── aggregate rendering ───
let currentFilter = 'all';

function renderAggregate(questions) {
  const list = document.getElementById('aggList');
  const countEl = document.getElementById('aggCount');

  const total = questions.reduce((s, q) => s + (q.count || 1), 0);
  const uniqueCount = questions.length;
  countEl.textContent = uniqueCount === 0
    ? 'No questions yet — be the first to ask'
    : `${total.toLocaleString()} total questions · ${uniqueCount.toLocaleString()} unique`;

  // filter
  let filtered = questions.slice();
  if (currentFilter === 'gap') filtered = filtered.filter(q => q.categoryId === 'other');
  else if (currentFilter === 'answer') filtered = filtered.filter(q => q.categoryId !== 'other');

  // sort by count desc, then lastAsked desc
  filtered.sort((a, b) => (b.count || 1) - (a.count || 1) || (b.lastAsked || 0) - (a.lastAsked || 0));
  filtered = filtered.slice(0, 20);

  list.innerHTML = '';
  if (filtered.length === 0) {
    list.innerHTML = `<li class="agg-empty">${currentFilter === 'gap'
      ? 'No unanswered questions yet. Ask something we don\u2019t cover above — the aggregate of gaps becomes a civic signal.'
      : currentFilter === 'answer'
        ? 'No questions yet that match the sections above. As residents ask, this list will populate.'
        : 'No questions yet. Be the first.'
    }</li>`;
    return;
  }

  for (const q of filtered) {
    const cat = CATEGORIES.find(c => c.id === q.categoryId);
    const hasAnswer = !!cat;
    const li = document.createElement('li');
    li.className = 'agg-item ' + (hasAnswer ? 'has-answer' : 'no-answer');
    const qText = escapeHTML(q.text);
    const count = q.count || 1;
    li.innerHTML = `
      <div class="agg-q">${qText}${hasAnswer ? ` <a class="agg-link" href="${cat.anchor}">&rarr; ${escapeHTML(cat.label)}</a>` : ''}</div>
      <span class="agg-count-chip">${count === 1 ? '1 ask' : count.toLocaleString() + ' asks'}</span>
      <span class="agg-status ${hasAnswer ? 'ok' : 'gap'}">${hasAnswer ? 'Has answer' : 'Gap'}</span>
    `;
    list.appendChild(li);
  }
}

function escapeHTML(s) {
  return String(s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

// ─── UI wiring ───
document.addEventListener('DOMContentLoaded', async () => {
  const form = document.getElementById('askForm');
  const input = document.getElementById('askInput');
  const submit = document.getElementById('askSubmit');
  const result = document.getElementById('askResult');
  const charCount = document.getElementById('askCharCount');

  input.addEventListener('input', () => {
    charCount.textContent = `${input.value.length} / ${MAX_Q_LENGTH}`;
  });

  document.querySelectorAll('.ask-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      input.value = chip.dataset.suggest;
      charCount.textContent = `${input.value.length} / ${MAX_Q_LENGTH}`;
      input.focus();
    });
  });

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const text = input.value.trim();
    if (!text) return;

    submit.disabled = true;
    submit.textContent = 'Sending…';
    result.className = 'ask-result';
    result.innerHTML = '';

    try {
      const res = await submitQuestion(text);
      if (res.status === 'reject') {
        result.className = 'ask-result err visible';
        result.innerHTML = `
          <div class="ask-result-head">One moment</div>
          <div class="ask-result-body">${escapeHTML(res.message)}</div>`;
      } else if (res.status === 'match') {
        const msg = res.matched && res.count > 1
          ? `<strong>${res.count.toLocaleString()} residents</strong> have asked about this. We have a section below.`
          : `Good question — we have a section on this.`;
        result.className = 'ask-result match visible';
        result.innerHTML = `
          <div class="ask-result-head">We have an answer for this</div>
          <div class="ask-result-body">${msg}${res.saved ? '' : '<br><em>(saved locally only — shared log unavailable)</em>'}</div>
          <a class="ask-result-link" href="${res.category.anchor}">Go to ${escapeHTML(res.category.label)} &rarr;</a>`;
        setTimeout(() => { document.querySelector(res.category.anchor)?.scrollIntoView({ behavior: 'smooth' }); }, 800);
      } else {
        // gap — uncovered question
        const msg = res.matched && res.count > 1
          ? `<strong>${res.count.toLocaleString()} residents</strong> have asked this kind of question — and we don\u2019t have a curated section for it yet. Your question is logged as a data gap.`
          : `You\u2019re the first to ask this, or the first to phrase it this way. We don\u2019t have a curated section for it yet. Your question is logged as a data gap — the aggregate of gaps is itself a civic signal for what to publish next.`;
        result.className = 'ask-result gap visible';
        result.innerHTML = `
          <div class="ask-result-head">This is a gap — logged</div>
          <div class="ask-result-body">${msg}${res.saved ? '' : '<br><em>(saved locally only — shared log unavailable)</em>'}</div>
          <a class="ask-result-link" href="#aggSection">See what others are asking &rarr;</a>`;
      }

      input.value = '';
      charCount.textContent = `0 / ${MAX_Q_LENGTH}`;
      // refresh aggregate
      const questions = inMemoryQuestions || await loadQuestions();
      renderAggregate(questions);
    } catch (err) {
      console.error(err);
      result.className = 'ask-result err visible';
      result.innerHTML = `
        <div class="ask-result-head">Something went wrong</div>
        <div class="ask-result-body">${escapeHTML(err.message || 'Unknown error')}. Your question wasn\u2019t saved.</div>`;
    } finally {
      submit.disabled = false;
      submit.textContent = 'Ask';
    }
  });

  // aggregate tab filtering
  document.querySelectorAll('.agg-tab').forEach(tab => {
    tab.addEventListener('click', async () => {
      document.querySelectorAll('.agg-tab').forEach(t => {
        t.classList.remove('active');
        t.setAttribute('aria-selected', 'false');
      });
      tab.classList.add('active');
      tab.setAttribute('aria-selected', 'true');
      currentFilter = tab.dataset.filter;
      const questions = inMemoryQuestions || await loadQuestions();
      renderAggregate(questions);
    });
  });

  // initial aggregate load
  try {
    const questions = await loadQuestions();
    renderAggregate(questions);
  } catch (err) {
    console.warn('Could not load aggregate:', err);
    renderAggregate([]);
  }
});

  // (No inline on* handlers detected — nothing to expose on window.)
})();
